final:
module RefModule(in_a, out_vt);input [1:0] in_a;
output out_vt;
reg   [2:0] unused_result;
assign out_vt = unused_result;

always @(*)
  begin
     unused_result    = 3'b000;
     case (in_a)
       2'b00 : begin
          unused_result = 3'b101;
       end

       2'b01: begin
          unused_result    = 3'b001;
       end

       default;

     endcase
  end
endmodule
